messages.message:
Patch Set 35:

Do we intent for lmv_mds_md_v1 and lmv_user_md_v1 to be the same size? And/or to have common fields at identical offsets? There are some pleces in llapi where this is assumed. It's hard to say how many other places implicityly assume this. This is not the case now.

struct lmv_user_md_v1 {
	__u32                      lum_magic;            /*     0     4 */
	__u32                      lum_stripe_count;     /*     4     4 */
	__u32                      lum_stripe_offset;    /*     8     4 */
	__u32                      lum_hash_type;        /*    12     4 */
	__u32                      lum_type;             /*    16     4 */
	__u32                      lum_padding1;         /*    20     4 */
	__u32                      lum_padding2;         /*    24     4 */
	__u32                      lum_padding3;         /*    28     4 */
	char                       lum_pool_name[16];    /*    32    16 */
	struct lmv_user_mds_data   lum_objects[0];       /*    48     0 */

	/* size: 48, cachelines: 1, members: 10 */
	/* last cacheline: 48 bytes */
};

struct lmv_mds_md_v1 {
	__u32                      lmv_magic;            /*     0     4 */
	__u32                      lmv_stripe_count;     /*     4     4 */
	__u32                      lmv_master_mdt_index; /*     8     4 */
	__u32                      lmv_hash_type;        /*    12     4 */
	__u32                      lmv_layout_version;   /*    16     4 */
	__u32                      lmv_padding;          /*    20     4 */
	struct lu_fid              lmv_master_fid;       /*    24    16 */
	char                       lmv_pool_name[16];    /*    40    16 */
	struct lu_fid              lmv_stripe_fids[0];   /*    56     0 */

	/* size: 56, cachelines: 1, members: 9 */
	/* last cacheline: 56 bytes */
};
